import React, { useState } from "react";
import FileUpload from "./components/FileUpload";
import Results from "./components/Results";
import "./App.css";

export default function App() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleUpload = async (file) => {
    setLoading(true);
    setError(null);
    setResult(null);

    const formData = new FormData();
    formData.append("file", file);

    try {
      const res = await fetch("http://localhost:8000/cluster", {
        method: "POST",
        body: formData,
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.detail || "Server error");
      setResult(data);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setResult(null);
    setError(null);
  };

  return (
    <div className="app">
      {/* ── Background grid ── */}
      <div className="bg-grid" aria-hidden="true" />

      {/* ── Header ── */}
      <header className="header">
        <div className="header-inner">
          <div className="logo">
            <span className="logo-mark">◈</span>
            <span className="logo-text">RFM<span className="logo-accent">seg</span></span>
          </div>
          <p className="header-sub">Customer Segmentation Engine</p>
        </div>
      </header>

      {/* ── Main ── */}
      <main className="main">
        {!result && !loading && (
          <FileUpload onUpload={handleUpload} error={error} />
        )}
        {loading && <LoadingState />}
        {result && <Results data={result} onReset={handleReset} />}
      </main>
    </div>
  );
}

function LoadingState() {
  const steps = [
    "Parsing transactions…",
    "Computing RFM metrics…",
    "Selecting optimal clusters…",
    "Profiling segments…",
  ];
  const [step, setStep] = React.useState(0);
  React.useEffect(() => {
    const t = setInterval(() => setStep((s) => Math.min(s + 1, steps.length - 1)), 1400);
    return () => clearInterval(t);
  }, []);
  return (
    <div className="loading-state">
      <div className="loader-ring">
        <div className="ring-inner" />
      </div>
      <p className="loading-step">{steps[step]}</p>
      <div className="loading-dots">
        {steps.map((s, i) => (
          <span key={i} className={`dot ${i <= step ? "active" : ""}`} />
        ))}
      </div>
    </div>
  );
}
